class Introduction(MovingCameraScene):

    def __init__(self, **kwargs):
        super().__init__(camera_class=MovingCamera, **kwargs)
        self.stream_lines_config = {}
        self.vector_field_config = {}
        self.virtual_time = 3

    def construct(self):

        def div_func(p):
            return p / 3
        div_vector_field = VectorField(div_func, **self.vector_field_config)
        stream_lines = StreamLines(div_func, **self.stream_lines_config)
        stream_lines.shuffle()
        div_title = self.get_title('Divergence')
        self.add(div_vector_field)
        self.play(LaggedStartMap(ShowPassingFlash, stream_lines), FadeIn(div_title[0]), *list(map(GrowFromCenter, div_title[1])))

        def curl_func(p):
            return rotate_vector(p / 3, 90 * DEGREES)
        curl_vector_field = VectorField(curl_func, **self.vector_field_config)
        stream_lines = StreamLines(curl_func, **self.stream_lines_config)
        stream_lines.shuffle()
        curl_title = self.get_title('Curl')
        self.play(ReplacementTransform(div_vector_field, curl_vector_field), ReplacementTransform(div_title, curl_title, path_arc=90 * DEGREES))
        self.play(ShowPassingFlash(stream_lines, run_time=3))
        self.wait()

    def get_title(self, word):
        title = Tex(word)
        title.scale(2)
        title.to_edge(UP)
        title.add_background_rectangle()
        return title

